param([string]$To="alex@1v1a.com",[string]$From="asferrazza@vectarr.com",[string]$Subject="Test - Updated asferrazza@vectarr.com Signature (Correct Format)")
try{$s=Get-Content "$env:APPDATA\Microsoft\Signatures\Vectarr (asferrazza@vectarr.com).htm"-Raw;$o=New-Object -ComObject Outlook.Application;$m=$o.CreateItem(0);$m.To=$To;$m.Subject=$Subject;$m.HTMLBody="<html><body style='font-family:Arial,sans-serif;'><p>This is a test with the corrected signature format matching the 3/5/26 version.</p><br>$s</body></html>";$a=$o.Session.Accounts|Where-Object{$_.SmtpAddress-eq$From};if($a){$m.SendUsingAccount=$a;Write-Host "Test email sent from $From with corrected signature"}else{Write-Warning "Account not found";exit 1};$m.Send()}catch{Write-Error "Failed: $_";exit 1}finally{if($m){[System.Runtime.Interopservices.Marshal]::ReleaseComObject($m)|Out-Null}if($o){[System.Runtime.Interopservices.Marshal]::ReleaseComObject($o)|Out-Null}}